// ── Scene 5: Capture live packets in Wireshark now ───────────────────────────

export const GeneratedScene5: React.FC<{ scene: SceneData }> = ({ scene }) => {
  const frame = useCurrentFrame();
  const { fps, width, height } = useVideoConfig();
  const totalFrames = Math.round(scene.duration_seconds * fps);
  const accent = scene.accent_color ?? "#00F2EA";

  // Background pulse glow — visible from frame 0
  const bgGlow = 0.25 + 0.15 * Math.sin(frame * 0.12);

  // Packet icons (TCP/UDP) spawning and spreading across MIDDLE ZONE
  const PACKETS = ["📦", "📤", "📥", "🔵", "🟢", "🔹"];
  const POSITIONS = [
    { x: 120, y: 600 },
    { x: 450, y: 550 },
    { x: 780, y: 610 },
    { x: 100, y: 900 },
    { x: 480, y: 950 },
    { x: 840, y: 880 },
  ];

  // Staggered spawn of packet icons
  const visiblePackets = Math.floor(
    interpolate(frame, [8, 60], [0, PACKETS.length], {
      extrapolateLeft: "clamp",
      extrapolateRight: "clamp",
    })
  );

  // Wireshark terminal box — starts animating from frame 50
  const terminalOpacity = interpolate(frame, [50, 70], [0, 1], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  });

  // Terminal text typing effect (simulating packet capture output)
  const terminalCmd =
    "$ sudo tcpdump -i en0\nCapturing packets...\n[TCP] 192.168.1.100 → 8.8.8.8:443\n[UDP] 192.168.1.101 → 1.1.1.1:53";
  const cmdLength = Math.floor(
    interpolate(frame, [55, 180], [0, terminalCmd.length], {
      extrapolateLeft: "clamp",
      extrapolateRight: "clamp",
    })
  );
  const displayedCmd = terminalCmd.slice(0, cmdLength);

  // Pulse wave effect (animated rings expanding outward from center)
  const wave1Scale = interpolate(frame, [20, 120], [0.3, 2.5], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  });
  const wave1Opacity = interpolate(frame, [20, 120], [0.8, 0], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  });

  const wave2Scale = interpolate(frame, [50, 150], [0.3, 2.5], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  });
  const wave2Opacity = interpolate(frame, [50, 150], [0.8, 0], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  });

  // Packet counter (number of packets captured)
  const packetCount = Math.floor(
    interpolate(frame, [0, totalFrames - 20], [0, 1847], {
      extrapolateLeft: "clamp",
      extrapolateRight: "clamp",
    })
  );
  const countScale = spring({
    frame: frame - 10,
    fps,
    config: { damping: 14, stiffness: 140 },
  });

  // Caption fade in
  const captionOpacity = interpolate(frame, [0, 25], [0, 1], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  });

  return (
    <AbsoluteFill
      style={{
        background: "#060609",
        overflow: "hidden",
        fontFamily: "monospace",
      }}
    >
      {/* Background radial pulse glow — visible from frame 0 */}
      <div
        style={{
          position: "absolute",
          top: 600,
          left: 180,
          width: 720,
          height: 720,
          borderRadius: "50%",
          background: `radial-gradient(circle, ${accent}20 0%, transparent 70%)`,
          opacity: bgGlow,
        }}
      />

      {/* TOP ZONE: Packet counter (y≈250) */}
      <div
        style={{
          position: "absolute",
          top: 220,
          left: 0,
          right: 0,
          textAlign: "center",
        }}
      >
        <div
          style={{
            fontSize: 140,
            fontWeight: 900,
            color: accent,
            textShadow: `0 0 50px ${accent}`,
            transform: `scale(${countScale})`,
            lineHeight: 1,
            opacity: 0.95,
          }}
        >
          {packetCount.toLocaleString()}
        </div>
        <div
          style={{
            fontSize: 38,
            color: "#E8E6E3",
            marginTop: 8,
            letterSpacing: 4,
          }}
        >
          PACKETS CAPTURED
        </div>
      </div>

      {/* MIDDLE ZONE: Pulse wave rings (centered at x=540, y=750) */}
      <svg
        style={{
          position: "absolute",
          top: 750,
          left: 540,
          width: 0,
          height: 0,
          overflow: "visible",
          transform: "translate(-50%, -50%)",
        }}
        width="600"
        height="600"
      >
        {/* Wave 1 - expanding ring */}
        <circle
          cx="0"
          cy="0"
          r={250 * wave1Scale}
          fill="none"
          stroke={accent}
          strokeWidth="3"
          opacity={wave1Opacity}
        />
        {/* Wave 2 - delayed expanding ring */}
        <circle
          cx="0"
          cy="0"
          r={250 * wave2Scale}
          fill="none"
          stroke={accent}
          strokeWidth="3"
          opacity={wave2Opacity}
        />
      </svg>

      {/* MIDDLE ZONE: Packet icons spawning with stagger (y=550-950) */}
      {POSITIONS.slice(0, visiblePackets).map((pos, i) => {
        const pkScale = spring({
          frame: frame - 8 - i * 7,
          fps,
          config: { damping: 11, stiffness: 190 },
        });
        const pkGlow =
          frame > 40 + i * 7 ? 0.5 + 0.5 * Math.sin((frame - 40) * 0.15) : 0;

        return (
          <div
            key={i}
            style={{
              position: "absolute",
              left: pos.x,
              top: pos.y,
              fontSize: 100,
              transform: `scale(${pkScale})`,
              opacity: 0.85,
              lineHeight: 1,
              filter: `drop-shadow(0 0 ${12 + pkGlow * 8}px ${accent})`,
            }}
          >
            {PACKETS[i]}
          </div>
        );
      })}

      {/* MIDDLE ZONE: Wireshark terminal box (y≈800-1100) */}
      <div
        style={{
          position: "absolute",
          top: 800,
          left: 80,
          right: 80,
          padding: 20,
          background: "rgba(0, 20, 40, 0.9)",
          border: `2px solid ${accent}`,
          borderRadius: 8,
          boxShadow: `0 0 30px ${accent}30`,
          opacity: terminalOpacity,
        }}
      >
        <div
          style={{
            fontSize: 38,
            color: accent,
            fontWeight: 700,
            marginBottom: 10,
            letterSpacing: 2,
          }}
        >
          $ Wireshark
        </div>
        <div
          style={{
            fontSize: 32,
            color: "#00FF41",
            whiteSpace: "pre-wrap",
            wordBreak: "break-word",
            lineHeight: 1.4,
            minHeight: 120,
          }}
        >
          {displayedCmd}
          {frame % 20 < 10 && cmdLength < terminalCmd.length ? "█" : " "}
        </div>
      </div>

      {/* BOTTOM ZONE: Progress bar (y=1260, above caption) */}
      <div
        style={{
          position: "absolute",
          top: 1260,
          left: 60,
          right: 60,
          height: 24,
          background: "#1a1a2e",
          borderRadius: 12,
          overflow: "hidden",
          boxShadow: `inset 0 0 8px rgba(0,0,0,0.8)`,
        }}
      >
        <div
          style={{
            width: `${Math.min(
              (packetCount / 1847) * 100,
              100
            )}%`,
            height: "100%",
            background: `linear-gradient(90deg, ${accent}, #00FFFF)`,
            borderRadius: 12,
            boxShadow: `0 0 16px ${accent}`,
            transition: "width 0.05s linear",
          }}
        />
      </div>

      {/* CAPTION — fixed at top:1350, never changes */}
      <div
        style={{
          position: "absolute",
          top: 1350,
          left: 60,
          right: 60,
          textAlign: "center",
          opacity: captionOpacity,
        }}
      >
        <p
          style={{
            color: "#E8E6E3",
            fontSize: 52,
            fontWeight: 900,
            lineHeight: 1.25,
            textShadow: "0 2px 12px rgba(0,0,0,0.9)",
            margin: 0,
          }}
        >
          {scene.caption}
        </p>
      </div>
    </AbsoluteFill>
  );
};

// ── Generated Scene Registry ─────────────────────────────────────────────────────
export const GENERATED_SCENE_REGISTRY: Record<string, React.FC<{ scene: SceneData }>> = {
  "scene-1": GeneratedScene0,
  "scene-2": GeneratedScene1,
  "scene-3": GeneratedScene2,
  "scene-4": GeneratedScene3,
  "scene-5": GeneratedScene4,
  "scene-6": GeneratedScene5,
};
